// Compute Sydney-local snapshot date + d1/d7/d28 window ISO timestamps.
const tz = 'Australia/Sydney';
const now = new Date();

function zonedYMD(date) {
  const fmt = new Intl.DateTimeFormat('en-CA', { timeZone: tz, year: 'numeric', month: '2-digit', day: '2-digit' });
  const parts = fmt.formatToParts(date);
  const obj = {};
  for (const p of parts) { if (p.type !== 'literal') obj[p.type] = p.value; }
  return `${obj.year}-${obj.month}-${obj.day}`;
}

function sydneyMidnightIso(dateStr) {
  const probe = new Date(`${dateStr}T12:00:00Z`);
  const dtf = new Intl.DateTimeFormat('en-US', { timeZone: tz, timeZoneName: 'shortOffset' });
  const parts = dtf.formatToParts(probe);
  const tzName = (parts.find(p => p.type === 'timeZoneName') || {}).value || 'GMT+10';
  const m = tzName.match(/GMT([+-])(\d{1,2})(?::?(\d{2}))?/);
  const sign = m ? m[1] : '+';
  const hh = m ? String(parseInt(m[2], 10)).padStart(2, '0') : '10';
  const mm = m && m[3] ? m[3] : '00';
  return `${dateStr}T00:00:00${sign}${hh}:${mm}`;
}

function subDaysStr(dateStr, n) {
  const d = new Date(`${dateStr}T00:00:00Z`);
  d.setUTCDate(d.getUTCDate() - n);
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth() + 1).padStart(2, '0')}-${String(d.getUTCDate()).padStart(2, '0')}`;
}

const todayStr = zonedYMD(now);
const snapshotDate = subDaysStr(todayStr, 1);

const endIso = sydneyMidnightIso(todayStr);
const startD1Iso = sydneyMidnightIso(snapshotDate);
const startD7Iso = sydneyMidnightIso(subDaysStr(todayStr, 7));
const startD28Iso = sydneyMidnightIso(subDaysStr(todayStr, 28));

return [{ json: { snapshotDate, endIso, startD1Iso, startD7Iso, startD28Iso, generatedAt: now.toISOString() } }];

// Build the platform_snapshots.metrics JSONB per Agent #10 contract v1.
// Supabase-only subset for dry-run — stripe/vercel/gsc emit null + source_missing.
function rows(nodeName) {
  const items = $(nodeName).all();
  const out = [];
  for (const it of items) {
    const p = it && it.json;
    if (!p) continue;
    if (Array.isArray(p)) { for (const r of p) if (r && typeof r === 'object' && r.id) out.push(r); }
    else if (Array.isArray(p.data)) { for (const r of p.data) if (r && typeof r === 'object' && r.id) out.push(r); }
    else if (typeof p === 'object' && p.id) { out.push(p); }
  }
  return out;
}
function maybeRows(nodeName) {
  const items = $(nodeName).all();
  const out = [];
  for (const it of items) {
    const p = it && it.json;
    if (!p) continue;
    if (Array.isArray(p)) { for (const r of p) if (r && typeof r === 'object') out.push(r); }
    else if (Array.isArray(p.data)) { for (const r of p.data) if (r && typeof r === 'object') out.push(r); }
    else if (typeof p === 'object' && (p.agent_name || p.date)) { out.push(p); }
  }
  return out;
}

const dates = $('Compute Snapshot Date').first().json;
const articles = rows('Read articles (d28)');
const editorial = rows('Read editorial_articles');
const pros = rows('Read professionals');
const prospects = rows('Read prospects');
const agentAnalytics = maybeRows('Read agent_analytics (d1)');

// Time helpers
const d1Start = new Date(dates.startD1Iso).getTime();
const d1End = new Date(dates.endIso).getTime();
const d7Start = new Date(dates.startD7Iso).getTime();

// content
const published = articles.filter(a => a.status === 'published');
const publishedInWindow = (ms) => published.filter(a => {
  const t = a.published_at ? new Date(a.published_at).getTime() : 0;
  return t >= ms && t < d1End;
}).length;
const tierOf = (a) => a.tier || (a.content_type === 'editorial' ? 2 : 3);
const tier1_published_d7 = published.filter(a => tierOf(a) === 1 && a.published_at && new Date(a.published_at).getTime() >= d7Start).length;
const tier2_published_d7 = published.filter(a => tierOf(a) === 2 && a.published_at && new Date(a.published_at).getTime() >= d7Start).length;
const tier3_published_d7 = published.filter(a => tierOf(a) === 3 && a.published_at && new Date(a.published_at).getTime() >= d7Start).length;
const drafts_in_review = editorial.filter(e => e.status === 'draft' || e.status === 'review_passed').length;
const drafts_awaiting_fin_objection = editorial.filter(e => e.status === 'review_passed' && !e.fin_objection_at).length;
const cumulative_published = published.length;

// sales
const prospects_added_d7 = prospects.filter(p => p.created_at && new Date(p.created_at).getTime() >= d7Start).length;
const prospects_active = prospects.filter(p => p.status && !['won','lost','unsubscribed'].includes(p.status)).length;
const advisor_trials_active = pros.filter(p => p.status === 'trial' || p.profile_quality_gate === 'pending').length;
const advisor_paid_active = pros.filter(p => p.status === 'active' && p.advisor_tier && p.advisor_tier !== 'bronze').length;

// agents (d1 rollup)
const by_agent = {};
let total_runs_d1 = 0; let total_errors_d1 = 0; let cost_aud_mtd = 0;
for (const r of agentAnalytics) {
  const name = r.agent_name || 'unknown';
  const runs = typeof r.total_logs === 'number' ? r.total_logs : 0;
  total_runs_d1 += runs;
  total_errors_d1 += typeof r.error_count === 'number' ? r.error_count : 0;
  // Estimated cost_usd -> AUD approx ×1.5
  const costAud = (typeof r.estimated_cost_usd === 'number' ? r.estimated_cost_usd : 0) * 1.5;
  cost_aud_mtd += costAud;
  by_agent[name] = {
    runs_d1: runs,
    success_rate_d7_pct: typeof r.success_rate === 'number' ? r.success_rate : null,
    cost_aud_mtd: costAud,
  };
}
const active_count = agentAnalytics.length;
const degraded_count = agentAnalytics.filter(r => typeof r.success_rate === 'number' && r.success_rate < 95 && r.success_rate >= 50).length;
const failed_count = agentAnalytics.filter(r => typeof r.success_rate === 'number' && r.success_rate < 50).length;

const source_missing = ['stripe', 'vercel_analytics', 'google_search_console'];
const source_ok = ['supabase', 'agent_runtime'];

const metrics = {
  version: 1,
  snapshot_date: dates.snapshotDate,
  generated_at: dates.generatedAt,
  generated_at_source_ages: {
    supabase: 'live',
    agent_runtime: 'live',
  },
  source_windows: { daily: '24h', rolling_7d: '7d', rolling_28d: '28d' },
  revenue: null,
  traffic: null,
  content: {
    tier1_published_d7,
    tier2_published_d7,
    tier3_published_d7,
    drafts_in_review,
    drafts_awaiting_fin_objection,
    cumulative_published,
  },
  sales: {
    prospects_added_d7,
    prospects_active,
    bd_pipeline_open_value_aud: null,
    advisor_trials_active,
    advisor_paid_active,
    trial_to_paid_d7_pct: null,
    api_customers_active: null,
    api_customers_trial: null,
  },
  product_health: null,
  agents: {
    active_count,
    degraded_count,
    failed_count,
    cost_aud_mtd,
    cost_aud_projected_monthly: null,
    by_agent,
    total_runs_d1,
    total_errors_d1,
  },
  ai_search: null,
  migration: null,
  data_quality: {
    source_ok,
    source_degraded: [],
    source_missing,
    notes: [
      'revenue/traffic/product_health/ai_search/migration are null because stripe/vercel/google_search_console MCPs are not wired up in this n8n instance yet (Phase 3 dry-run).',
    ],
  },
};

return [{ json: { snapshot_date: dates.snapshotDate, source_agent: 'analytics', metrics } }];
